#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long n, k;
        scanf("%lld %lld", &n, &k);
        long long count = 0;
        for (long long a = n + 1; a < k; a++) {
            for (long long b = n + 1; b < k; b++) {
                if ((a * b - n) % ((a - n) * (b - n)) == 0) {
                    count++;
                }
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

