        while (T-- > 0) {
            long n = sc.nextLong();
            long k = sc.nextLong();
            long count = 0;
            for (long a = n + 1; a < k; a++) {
                for (long b = n + 1; b < k; b++) {
                    if ((a * b - n) % ((a - n) * (b - n)) == 0) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
